"use client";

import { useCallback, useEffect, useMemo, useState } from "react";
import { Brain } from "lucide-react";

import {
  Button,
  Input,
  Label,
  SectionHeader,
  SectionPanel,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
  Textarea,
  useToast,
} from "@/shared/ui";
import { cn } from "@/shared/utils";
import { useSettingsMap, useUpdateSetting } from "@/shared/hooks/use-settings";
import { serializeSetting } from "@/shared/utils/settings-json";
import { logClientError } from "@/features/observability";

import {
  AI_BRAIN_SETTINGS_KEY,
  defaultBrainSettings,
  parseBrainSettings,
  resolveBrainAssignment,
  sanitizeBrainAssignment,
  type AiBrainAssignment,
  type AiBrainFeature,
  type AiBrainProvider,
  type AiBrainSettings,
} from "../settings";

type FeatureConfig = {
  key: AiBrainFeature;
  label: string;
  description: string;
};

const FEATURES: FeatureConfig[] = [
  {
    key: "cms_builder",
    label: "CMS Builder",
    description: "Theme/style generation and design assistants inside the CMS Builder.",
  },
  {
    key: "image_studio",
    label: "Image Studio",
    description: "Prompt extraction, UI extractor, and prompt learning for Image Studio.",
  },
  {
    key: "prompt_engine",
    label: "Prompt Engine",
    description: "Validation learning and prompt tooling shared across the app.",
  },
  {
    key: "ai_paths",
    label: "AI Paths",
    description: "Default model settings for AI Paths model nodes.",
  },
  {
    key: "analytics",
    label: "Analytics",
    description: "AI analytics summaries and warnings across the dashboard.",
  },
  {
    key: "system_logs",
    label: "System Logs",
    description: "AI summaries and insights in the System Logs dashboard.",
  },
  {
    key: "error_logs",
    label: "Error Logs",
    description: "AI interpretation and diagnostics for error log entries.",
  },
];

const providerOptions: Array<{ value: AiBrainProvider; label: string }> = [
  { value: "model", label: "Model" },
  { value: "agent", label: "Agent" },
];

const buildAssignment = (): AiBrainAssignment => ({ ...defaultBrainSettings.defaults });

const AssignmentEditor = ({
  assignment,
  onChange,
  readOnly,
}: {
  assignment: AiBrainAssignment;
  onChange: (next: AiBrainAssignment) => void;
  readOnly?: boolean;
}): React.JSX.Element => {
  const updateField = (patch: Partial<AiBrainAssignment>): void => {
    onChange({ ...assignment, ...patch });
  };

  return (
    <div className={cn("grid gap-3", readOnly ? "opacity-70" : "")}
      aria-disabled={!!readOnly}
    >
      <label className="flex items-center gap-2 text-xs text-gray-300">
        <input
          type="checkbox"
          className="h-3 w-3 rounded border-gray-600"
          checked={assignment.enabled}
          onChange={(e: React.ChangeEvent<HTMLInputElement>) => updateField({ enabled: e.target.checked })}
          disabled={!!readOnly}
        />
        Enabled
      </label>

      <div className="grid gap-2 md:grid-cols-2">
        <div className="space-y-1">
          <Label className="text-xs text-gray-400">Provider</Label>
          <Select
            value={assignment.provider}
            onValueChange={(value: string) => updateField({ provider: value as AiBrainProvider })}
            disabled={!!readOnly}
          >
            <SelectTrigger className="h-9">
              <SelectValue placeholder="Select provider" />
            </SelectTrigger>
            <SelectContent>
              {providerOptions.map((opt: { value: AiBrainProvider; label: string }) => (
                <SelectItem key={opt.value} value={opt.value}>
                  {opt.label}
                </SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
        <div className="space-y-1">
          <Label className="text-xs text-gray-400">Model ID</Label>
          <Input
            value={assignment.modelId}
            onChange={(e: React.ChangeEvent<HTMLInputElement>) => updateField({ modelId: e.target.value })}
            placeholder="gpt-4o-mini"
            disabled={!!readOnly || assignment.provider !== "model"}
          />
        </div>
        <div className="space-y-1">
          <Label className="text-xs text-gray-400">Agent ID</Label>
          <Input
            value={assignment.agentId}
            onChange={(e: React.ChangeEvent<HTMLInputElement>) => updateField({ agentId: e.target.value })}
            placeholder="agent_xxx"
            disabled={!!readOnly || assignment.provider !== "agent"}
          />
        </div>
        <div className="space-y-1">
          <Label className="text-xs text-gray-400">Temperature</Label>
          <Input
            type="number"
            min={0}
            max={2}
            step={0.1}
            value={assignment.temperature ?? ""}
            onChange={(e: React.ChangeEvent<HTMLInputElement>) => updateField({ temperature: e.target.value === "" ? undefined : Number(e.target.value) })}
            disabled={!!readOnly}
          />
        </div>
        <div className="space-y-1">
          <Label className="text-xs text-gray-400">Max tokens</Label>
          <Input
            type="number"
            min={1}
            max={8192}
            step={1}
            value={assignment.maxTokens ?? ""}
            onChange={(e: React.ChangeEvent<HTMLInputElement>) => updateField({ maxTokens: e.target.value === "" ? undefined : Number(e.target.value) })}
            disabled={!!readOnly}
          />
        </div>
      </div>

      <div className="space-y-1">
        <Label className="text-xs text-gray-400">Notes</Label>
        <Textarea
          className="min-h-[72px] text-xs"
          value={assignment.notes ?? ""}
          onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => updateField({ notes: e.target.value })}
          placeholder="Optional notes for this assignment"
          disabled={!!readOnly}
        />
      </div>
    </div>
  );
};

export function AdminBrainPage(): React.JSX.Element {
  const { toast } = useToast();
  const settingsQuery = useSettingsMap();
  const updateSetting = useUpdateSetting();

  const [settings, setSettings] = useState<AiBrainSettings>(defaultBrainSettings);
  const [overridesEnabled, setOverridesEnabled] = useState<Record<AiBrainFeature, boolean>>({
    cms_builder: false,
    image_studio: false,
    prompt_engine: false,
    ai_paths: false,
    analytics: false,
    system_logs: false,
    error_logs: false,
  });
  const [initializedAt, setInitializedAt] = useState<number | null>(null);

  useEffect((): void => {
    if (settingsQuery.isSuccess && initializedAt !== settingsQuery.dataUpdatedAt) {
      setInitializedAt(settingsQuery.dataUpdatedAt);
      const parsed = parseBrainSettings(settingsQuery.data.get(AI_BRAIN_SETTINGS_KEY));
      setSettings(parsed);
      setOverridesEnabled({
        cms_builder: Boolean(parsed.assignments.cms_builder),
        image_studio: Boolean(parsed.assignments.image_studio),
        prompt_engine: Boolean(parsed.assignments.prompt_engine),
        ai_paths: Boolean(parsed.assignments.ai_paths),
        analytics: Boolean(parsed.assignments.analytics),
        system_logs: Boolean(parsed.assignments.system_logs),
        error_logs: Boolean(parsed.assignments.error_logs),
      });
    }
  }, [settingsQuery.isSuccess, settingsQuery.dataUpdatedAt, settingsQuery.data, initializedAt]);

  const effectiveAssignments = useMemo((): Record<AiBrainFeature, AiBrainAssignment> => {
    return FEATURES.reduce<Record<AiBrainFeature, AiBrainAssignment>>((acc: Record<AiBrainFeature, AiBrainAssignment>, feature: FeatureConfig) => {
      acc[feature.key] = resolveBrainAssignment(settings, feature.key);
      return acc;
    }, {} as Record<AiBrainFeature, AiBrainAssignment>);
  }, [settings]);

  const handleDefaultChange = useCallback((next: AiBrainAssignment): void => {
    setSettings((prev: AiBrainSettings) => ({
      ...prev,
      defaults: sanitizeBrainAssignment(next),
    }));
  }, []);

  const handleOverrideChange = useCallback((feature: AiBrainFeature, next: AiBrainAssignment): void => {
    setSettings((prev: AiBrainSettings) => ({
      ...prev,
      assignments: {
        ...prev.assignments,
        [feature]: sanitizeBrainAssignment(next),
      },
    }));
  }, []);

  const toggleOverride = useCallback((feature: AiBrainFeature, enabled: boolean): void => {
    setOverridesEnabled((prev: Record<AiBrainFeature, boolean>) => ({ ...prev, [feature]: enabled }));
    if (!enabled) {
      setSettings((prev: AiBrainSettings) => {
        const nextAssignments = { ...prev.assignments };
        delete nextAssignments[feature];
        return { ...prev, assignments: nextAssignments };
      });
    } else {
    setSettings((prev: AiBrainSettings) => ({
      ...prev,
      assignments: {
        ...prev.assignments,
        [feature]: prev.assignments[feature] ?? resolveBrainAssignment(prev, feature),
      },
    }));
    }
  }, []);

  const handleSave = useCallback(async (): Promise<void> => {
    try {
      const next: AiBrainSettings = {
        ...settings,
        defaults: sanitizeBrainAssignment(settings.defaults),
        assignments: {
          ...(overridesEnabled.cms_builder ? { cms_builder: sanitizeBrainAssignment(settings.assignments.cms_builder ?? buildAssignment()) } : {}),
          ...(overridesEnabled.image_studio ? { image_studio: sanitizeBrainAssignment(settings.assignments.image_studio ?? buildAssignment()) } : {}),
          ...(overridesEnabled.prompt_engine ? { prompt_engine: sanitizeBrainAssignment(settings.assignments.prompt_engine ?? buildAssignment()) } : {}),
          ...(overridesEnabled.ai_paths ? { ai_paths: sanitizeBrainAssignment(settings.assignments.ai_paths ?? buildAssignment()) } : {}),
          ...(overridesEnabled.analytics ? { analytics: sanitizeBrainAssignment(settings.assignments.analytics ?? buildAssignment()) } : {}),
          ...(overridesEnabled.system_logs ? { system_logs: sanitizeBrainAssignment(settings.assignments.system_logs ?? buildAssignment()) } : {}),
          ...(overridesEnabled.error_logs ? { error_logs: sanitizeBrainAssignment(settings.assignments.error_logs ?? buildAssignment()) } : {}),
        },
      };
      await updateSetting.mutateAsync({
        key: AI_BRAIN_SETTINGS_KEY,
        value: serializeSetting(next),
      });
      toast("Brain settings saved.", { variant: "success" });
    } catch (error) {
      logClientError(error, { context: { source: "AdminBrainPage", action: "save" } });
      toast("Failed to save Brain settings.", { variant: "error" });
    }
  }, [overridesEnabled, settings, toast, updateSetting]);

  const handleReset = useCallback((): void => {
    setSettings(defaultBrainSettings);
    setOverridesEnabled({
      cms_builder: false,
      image_studio: false,
      prompt_engine: false,
      ai_paths: false,
      analytics: false,
      system_logs: false,
      error_logs: false,
    });
  }, []);

  useEffect((): void => {
    const raw = settingsQuery.data?.get(AI_BRAIN_SETTINGS_KEY);
    if (!raw && settingsQuery.isSuccess && initializedAt === settingsQuery.dataUpdatedAt) {
      setSettings((prev: AiBrainSettings) => {
        if (prev === defaultBrainSettings) return prev;
        return defaultBrainSettings;
      });
    }
  }, [initializedAt, settingsQuery.data, settingsQuery.dataUpdatedAt, settingsQuery.isSuccess]);

  return (
    <div className="space-y-4">
      <SectionHeader
        eyebrow="System"
        title="Brain"
        icon={<Brain className="size-5 text-emerald-300" />}
        description="Centralized AI steering for the app. Configure defaults and override AI assignments per feature."
        actions={
          <>
            <Button variant="outline" size="sm" onClick={handleReset}>
              Reset
            </Button>
            <Button size="sm" onClick={() => void handleSave()} disabled={updateSetting.isPending}>
              {updateSetting.isPending ? "Saving..." : "Save"}
            </Button>
          </>
        }
      />

      <SectionPanel variant="subtle">
        <div className="flex items-center justify-between gap-2 text-xs text-gray-400">
          <div>Assignments are applied instantly to AI routing across the product.</div>
          <div>Source: {settingsQuery.data?.get(AI_BRAIN_SETTINGS_KEY) ? "saved settings" : "defaults"}</div>
        </div>
      </SectionPanel>

      <SectionPanel>
        <div className="text-xs uppercase text-gray-500">Global defaults</div>
        <div className="mt-2">
          <AssignmentEditor assignment={settings.defaults} onChange={handleDefaultChange} />
        </div>
      </SectionPanel>

      <div className="grid gap-4 md:grid-cols-2">
        {FEATURES.map((feature: FeatureConfig) => {
          const overrideEnabled = overridesEnabled[feature.key];
          const assignment = overrideEnabled
            ? settings.assignments[feature.key] ?? effectiveAssignments[feature.key]
            : effectiveAssignments[feature.key];
          return (
            <SectionPanel key={feature.key}>
              <div className="flex items-start justify-between gap-2">
                <div>
                  <div className="text-sm font-semibold text-gray-100">{feature.label}</div>
                  <div className="text-xs text-gray-400">{feature.description}</div>
                </div>
                <label className="flex items-center gap-2 text-[11px] text-gray-400">
                  <input
                    type="checkbox"
                    className="h-3 w-3 rounded border-gray-600"
                    checked={overrideEnabled}
                    onChange={(e: React.ChangeEvent<HTMLInputElement>) => toggleOverride(feature.key, e.target.checked)}
                  />
                  Override
                </label>
              </div>

              <div className="mt-3">
                <AssignmentEditor
                  assignment={assignment}
                  onChange={(next: AiBrainAssignment) => handleOverrideChange(feature.key, next)}
                  readOnly={!overrideEnabled}
                />
              </div>

              {!overrideEnabled ? (
                <div className="mt-2 text-[11px] text-gray-500">Using global defaults.</div>
              ) : null}
            </SectionPanel>
          );
        })}
      </div>
    </div>
  );
}

"use client";

import { useCallback, useMemo, useState } from "react";
import Link from "next/link";
import { RefreshCcw } from "lucide-react";

import {
  Button,
  Input,
  Label,
  SectionHeader,
  SectionPanel,
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
  Textarea,
  useToast,
} from "@/shared/ui";
import { cn } from "@/shared/utils";
import { useUpdateSetting } from "@/shared/hooks/use-settings";
import { useSettingsStore } from "@/shared/providers/SettingsStoreProvider";
import { serializeSetting } from "@/shared/utils/settings-json";
import { logClientError } from "@/features/observability";

import {
  defaultImageStudioSettings,
  IMAGE_STUDIO_SETTINGS_KEY,
  parseImageStudioSettings,
  type ImageStudioSettings,
} from "../utils/studio-settings";
import {
  defaultPromptEngineSettings,
  PROMPT_ENGINE_SETTINGS_KEY,
  parsePromptEngineSettings,
  parsePromptValidationRules,
} from "@/features/prompt-engine/settings";

export function AdminImageStudioSettingsPage(): React.JSX.Element {
  const { toast } = useToast();
  const settingsStore = useSettingsStore();
  const updateSetting = useUpdateSetting();

  const [settingsLoaded, setSettingsLoaded] = useState<boolean>(false);
  const [studioSettings, setStudioSettings] = useState<ImageStudioSettings>(defaultImageStudioSettings);
  const [advancedOverridesText, setAdvancedOverridesText] = useState<string>(
    JSON.stringify(defaultImageStudioSettings.targetAi.openai.advanced_overrides ?? {}, null, 2)
  );
  const [advancedOverridesError, setAdvancedOverridesError] = useState<string | null>(null);
  const [promptValidationRulesText, setPromptValidationRulesText] = useState<string>(
    JSON.stringify(defaultPromptEngineSettings.promptValidation.rules, null, 2)
  );
  const [promptValidationRulesError, setPromptValidationRulesError] = useState<string | null>(null);

  // Derived state for settings initialization
  const [prevSettingsData, setPrevSettingsData] = useState<unknown>(null);
  const promptEngineRaw = settingsStore.get(PROMPT_ENGINE_SETTINGS_KEY);
  const promptEngineSettings = useMemo(
    () => parsePromptEngineSettings(promptEngineRaw),
    [promptEngineRaw]
  );

  if (settingsStore.map && settingsStore.map !== prevSettingsData && !settingsLoaded) {
    setPrevSettingsData(settingsStore.map);

    const stored = parseImageStudioSettings(settingsStore.get(IMAGE_STUDIO_SETTINGS_KEY));
    const promptEngineStored = parsePromptEngineSettings(settingsStore.get(PROMPT_ENGINE_SETTINGS_KEY));
    const openaiModelFallback = settingsStore.get("openai_model");

    const hydrated: ImageStudioSettings =
      openaiModelFallback && stored.targetAi.openai.model === defaultImageStudioSettings.targetAi.openai.model
        ? {
            ...stored,
            targetAi: {
              ...stored.targetAi,
              openai: {
                ...stored.targetAi.openai,
                model: openaiModelFallback,
              },
            },
          }
        : stored;

    setStudioSettings(hydrated);
    setAdvancedOverridesText(JSON.stringify(hydrated.targetAi.openai.advanced_overrides ?? {}, null, 2));
    setPromptValidationRulesText(JSON.stringify(promptEngineStored.promptValidation.rules, null, 2));
    setPromptValidationRulesError(null);
    setSettingsLoaded(true);
  }

  const handleRefresh = useCallback((): void => {
    setSettingsLoaded(false);
    settingsStore.refetch();
  }, [settingsStore.refetch]);

  const handleAdvancedOverridesChange = useCallback((raw: string): void => {
    setAdvancedOverridesText(raw);
    try {
      const parsed = JSON.parse(raw) as unknown;
      if (parsed === null) {
        setAdvancedOverridesError(null);
        setStudioSettings((prev: ImageStudioSettings) => ({
          ...prev,
          targetAi: { ...prev.targetAi, openai: { ...prev.targetAi.openai, advanced_overrides: null } },
        }));
        return;
      }
      if (!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
        setAdvancedOverridesError("Must be a JSON object (or null).");
        return;
      }
      setAdvancedOverridesError(null);
      setStudioSettings((prev: ImageStudioSettings) => ({
        ...prev,
        targetAi: {
          ...prev.targetAi,
          openai: { ...prev.targetAi.openai, advanced_overrides: parsed as Record<string, unknown> },
        },
      }));
    } catch {
      setAdvancedOverridesError("Invalid JSON.");
    }
  }, []);

  const handlePromptValidationRulesChange = useCallback((raw: string): void => {
    setPromptValidationRulesText(raw);
    const parsed = parsePromptValidationRules(raw);
    if (!parsed.ok) {
      setPromptValidationRulesError(parsed.error);
      return;
    }
    setPromptValidationRulesError(null);
  }, []);

  const saveStudioSettings = useCallback(async (): Promise<void> => {
    if (advancedOverridesError) {
      toast(`Settings not saved: ${advancedOverridesError}`, { variant: "error" });
      return;
    }
    if (promptValidationRulesError) {
      toast(`Settings not saved: ${promptValidationRulesError}`, { variant: "error" });
      return;
    }

    if (studioSettings.promptExtraction.mode === "gpt" && !studioSettings.promptExtraction.gpt.model.trim()) {
      toast("Prompt extract model is required when prompt extraction mode is GPT.", { variant: "error" });
      return;
    }

    if (!studioSettings.targetAi.openai.model.trim()) {
      toast("Target AI model is required.", { variant: "error" });
      return;
    }

    try {
      await updateSetting.mutateAsync({
        key: IMAGE_STUDIO_SETTINGS_KEY,
        value: serializeSetting(studioSettings),
      });
      const parsedRules = parsePromptValidationRules(promptValidationRulesText);
      if (!parsedRules.ok) {
        throw new Error(parsedRules.error);
      }
      await updateSetting.mutateAsync({
        key: PROMPT_ENGINE_SETTINGS_KEY,
        value: serializeSetting({
          ...promptEngineSettings,
          promptValidation: { ...promptEngineSettings.promptValidation, rules: parsedRules.rules },
        }),
      });
      toast("Image Studio settings saved.", { variant: "success" });
    } catch (error) {
      logClientError(error, { context: { source: "AdminImageStudioSettingsPage", action: "saveSettings" } });
      toast("Failed to save Image Studio settings.", { variant: "error" });
    }
  }, [advancedOverridesError, promptValidationRulesError, studioSettings, promptValidationRulesText, promptEngineSettings, toast, updateSetting]);

  const resetStudioSettings = useCallback((): void => {
    setStudioSettings(defaultImageStudioSettings);
    setAdvancedOverridesText(JSON.stringify(defaultImageStudioSettings.targetAi.openai.advanced_overrides ?? {}, null, 2));
    setAdvancedOverridesError(null);
    setPromptValidationRulesText(JSON.stringify(defaultPromptEngineSettings.promptValidation.rules, null, 2));
    setPromptValidationRulesError(null);
  }, []);

  const studioSettingsRaw = settingsStore.get(IMAGE_STUDIO_SETTINGS_KEY);

  const settingsSource = useMemo(() => {
    return studioSettingsRaw ? "saved settings" : "defaults";
  }, [studioSettingsRaw]);

  return (
    <div className="space-y-4">
      <SectionHeader
        eyebrow="AI · Image Studio"
        title="Settings"
        description="Configure prompt extraction, prompt validation, and target AI defaults."
        actions={
          <>
            <Button type="button" variant="outline" asChild>
              <Link href="/admin/image-studio">Back to Studio</Link>
            </Button>
            <Button type="button" variant="outline" asChild>
              <Link href="/admin/prompt-engine/validation">Global Validation Patterns</Link>
            </Button>
            <Button
              type="button"
              variant="outline"
              onClick={() => void handleRefresh()}
              disabled={settingsStore.isFetching}
              title="Reload settings"
            >
              <RefreshCcw className={cn("mr-2 size-4", settingsStore.isFetching ? "animate-spin" : "")} />
              Refresh
            </Button>
          </>
        }
      />

      <SectionPanel variant="subtle">
        <div className="flex flex-wrap items-center justify-between gap-2">
          <div className="text-xs text-gray-300">Studio Settings</div>
          <div className="flex items-center gap-2">
            <Button
              variant="outline"
              size="sm"
              onClick={resetStudioSettings}
              disabled={updateSetting.isPending}
            >
              Reset
            </Button>
            <Button
              size="sm"
              onClick={() => void saveStudioSettings()}
              disabled={updateSetting.isPending || Boolean(advancedOverridesError) || Boolean(promptValidationRulesError)}
            >
              {updateSetting.isPending ? "Saving..." : "Save"}
            </Button>
          </div>
        </div>

        <div className="mt-1 text-[11px] text-gray-500">
          Source: {settingsSource}
        </div>

        {settingsStore.isLoading && !settingsLoaded ? (
          <div className="mt-2 text-xs text-gray-500">Loading settings…</div>
        ) : null}

        <div className="mt-4 space-y-4">
          <div className="space-y-2">
            <Label className="text-xs text-gray-400">Prompt Extraction</Label>
            <div className="grid grid-cols-2 gap-2">
              <div className="space-y-1">
                <div className="text-[11px] text-gray-500">Mode</div>
                <Select
                  value={studioSettings.promptExtraction.mode}
                  onValueChange={(value: string) =>
                    setStudioSettings((prev: ImageStudioSettings) => ({
                      ...prev,
                      promptExtraction: {
                        ...prev.promptExtraction,
                        mode: value === "gpt" ? "gpt" : "programmatic",
                      },
                    }))
                  }
                >
                  <SelectTrigger className="h-8">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="programmatic">Programmatic</SelectItem>
                    <SelectItem value="gpt">GPT (AI)</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-1">
                <div className="text-[11px] text-gray-500">Model</div>
                <Input
                  value={studioSettings.promptExtraction.gpt.model}
                  onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
                    setStudioSettings((prev: ImageStudioSettings) => ({
                      ...prev,
                      promptExtraction: {
                        ...prev.promptExtraction,
                        gpt: { ...prev.promptExtraction.gpt, model: e.target.value },
                      },
                    }))
                  }
                  className="h-8"
                  placeholder="e.g. gpt-4o-mini"
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-2">
              <div className="space-y-1">
                <div className="text-[11px] text-gray-500">Temperature</div>
                <Input
                  type="number"
                  value={studioSettings.promptExtraction.gpt.temperature ?? ""}
                  onChange={(e: React.ChangeEvent<HTMLInputElement>) => {
                    const raw = e.target.value;
                    const next = raw === "" ? null : Number(raw);
                    if (raw !== "" && !Number.isFinite(next)) return;
                    setStudioSettings((prev: ImageStudioSettings) => ({
                      ...prev,
                      promptExtraction: {
                        ...prev.promptExtraction,
                        gpt: { ...prev.promptExtraction.gpt, temperature: next },
                      },
                    }));
                  }}
                  className="h-8"
                  min={0}
                  max={2}
                  step={0.1}
                />
              </div>
              <div className="space-y-1">
                <div className="text-[11px] text-gray-500">Top P</div>
                <Input
                  type="number"
                  value={studioSettings.promptExtraction.gpt.top_p ?? ""}
                  onChange={(e: React.ChangeEvent<HTMLInputElement>) => {
                    const raw = e.target.value;
                    const next = raw === "" ? null : Number(raw);
                    if (raw !== "" && !Number.isFinite(next)) return;
                    setStudioSettings((prev: ImageStudioSettings) => ({
                      ...prev,
                      promptExtraction: {
                        ...prev.promptExtraction,
                        gpt: { ...prev.promptExtraction.gpt, top_p: next },
                      },
                    }));
                  }}
                  className="h-8"
                  min={0}
                  max={1}
                  step={0.05}
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-2">
              <div className="space-y-1">
                <div className="text-[11px] text-gray-500">Max Output Tokens</div>
                <Input
                  type="number"
                  value={studioSettings.promptExtraction.gpt.max_output_tokens ?? ""}
                  onChange={(e: React.ChangeEvent<HTMLInputElement>) => {
                    const raw = e.target.value;
                    const next = raw === "" ? null : Number(raw);
                    if (raw !== "" && (!Number.isFinite(next) || !Number.isInteger(next))) return;
                    setStudioSettings((prev: ImageStudioSettings) => ({
                      ...prev,
                      promptExtraction: {
                        ...prev.promptExtraction,
                        gpt: { ...prev.promptExtraction.gpt, max_output_tokens: next },
                      },
                    }));
                  }}
                  className="h-8"
                  min={1}
                  step={1}
                />
              </div>
              <div className="text-[11px] text-gray-500">
                Used by the AI extract button in Image Studio.
              </div>
            </div>
          </div>

          <div className="space-y-2">
            <div className="flex items-center justify-between gap-2">
              <Label className="text-xs text-gray-400">Prompt Validator</Label>
              <label className="flex items-center gap-2 text-xs text-gray-200">
                <input
                  type="checkbox"
                  checked={studioSettings.promptValidation.enabled}
                  onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
                    setStudioSettings((prev: ImageStudioSettings) => ({
                      ...prev,
                      promptValidation: { ...prev.promptValidation, enabled: e.target.checked },
                    }))
                  }
                />
                Enabled
              </label>
            </div>
            <div className="text-[11px] text-gray-500">
              Validates programmatic prompts and suggests fixes when patterns look almost correct. Auto format uses each rule’s <span className="text-gray-300">autofix</span> operations.
            </div>
            <Textarea
              value={promptValidationRulesText}
              onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => handlePromptValidationRulesChange(e.target.value)}
              className="h-40 font-mono text-[11px]"
              placeholder="JSON array of validator rules"
            />
            {promptValidationRulesError ? (
              <div className="text-[11px] text-red-300">{promptValidationRulesError}</div>
            ) : null}
          </div>

          <div className="space-y-2">
            <Label className="text-xs text-gray-400">Target AI (OpenAI / GPT)</Label>

            <div className="grid grid-cols-2 gap-2">
              <div className="space-y-1">
                <div className="text-[11px] text-gray-500">API</div>
                <Select
                  value={studioSettings.targetAi.openai.api}
                  onValueChange={(value: string) =>
                    setStudioSettings((prev: ImageStudioSettings) => ({
                      ...prev,
                      targetAi: { ...prev.targetAi, openai: { ...prev.targetAi.openai, api: value === "responses" ? "responses" : "images" } },
                    }))
                  }
                >
                  <SelectTrigger className="h-8">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="images">Images</SelectItem>
                    <SelectItem value="responses">Responses</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-1">
                <div className="text-[11px] text-gray-500">Model</div>
                <Input
                  value={studioSettings.targetAi.openai.model}
                  onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
                    setStudioSettings((prev: ImageStudioSettings) => ({
                      ...prev,
                      targetAi: { ...prev.targetAi, openai: { ...prev.targetAi.openai, model: e.target.value } },
                    }))
                  }
                  className="h-8"
                  placeholder={studioSettings.targetAi.openai.api === "images" ? "e.g. gpt-image-1" : "e.g. gpt-4o-mini"}
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-2">
              <div className="space-y-1">
                <div className="text-[11px] text-gray-500">Temperature</div>
                <Input
                  type="number"
                  value={studioSettings.targetAi.openai.temperature ?? ""}
                  onChange={(e: React.ChangeEvent<HTMLInputElement>) => {
                    const raw = e.target.value;
                    const next = raw === "" ? null : Number(raw);
                    if (raw !== "" && !Number.isFinite(next)) return;
                    setStudioSettings((prev: ImageStudioSettings) => ({
                      ...prev,
                      targetAi: { ...prev.targetAi, openai: { ...prev.targetAi.openai, temperature: next } },
                    }));
                  }}
                  className="h-8"
                  min={0}
                  max={2}
                  step={0.1}
                />
              </div>
              <div className="space-y-1">
                <div className="text-[11px] text-gray-500">Top P</div>
                <Input
                  type="number"
                  value={studioSettings.targetAi.openai.top_p ?? ""}
                  onChange={(e: React.ChangeEvent<HTMLInputElement>) => {
                    const raw = e.target.value;
                    const next = raw === "" ? null : Number(raw);
                    if (raw !== "" && !Number.isFinite(next)) return;
                    setStudioSettings((prev: ImageStudioSettings) => ({
                      ...prev,
                      targetAi: { ...prev.targetAi, openai: { ...prev.targetAi.openai, top_p: next } },
                    }));
                  }}
                  className="h-8"
                  min={0}
                  max={1}
                  step={0.05}
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-2">
              <div className="space-y-1">
                <div className="text-[11px] text-gray-500">Max Output Tokens</div>
                <Input
                  type="number"
                  value={studioSettings.targetAi.openai.max_output_tokens ?? ""}
                  onChange={(e: React.ChangeEvent<HTMLInputElement>) => {
                    const raw = e.target.value;
                    const next = raw === "" ? null : Number(raw);
                    if (raw !== "" && (!Number.isFinite(next) || !Number.isInteger(next))) return;
                    setStudioSettings((prev: ImageStudioSettings) => ({
                      ...prev,
                      targetAi: { ...prev.targetAi, openai: { ...prev.targetAi.openai, max_output_tokens: next } },
                    }));
                  }}
                  className="h-8"
                  min={1}
                  step={1}
                />
              </div>
              <div className="space-y-1">
                <div className="text-[11px] text-gray-500">Seed</div>
                <Input
                  type="number"
                  value={studioSettings.targetAi.openai.seed ?? ""}
                  onChange={(e: React.ChangeEvent<HTMLInputElement>) => {
                    const raw = e.target.value;
                    const next = raw === "" ? null : Number(raw);
                    if (raw !== "" && (!Number.isFinite(next) || !Number.isInteger(next))) return;
                    setStudioSettings((prev: ImageStudioSettings) => ({
                      ...prev,
                      targetAi: { ...prev.targetAi, openai: { ...prev.targetAi.openai, seed: next } },
                    }));
                  }}
                  className="h-8"
                  step={1}
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-2">
              <div className="space-y-1">
                <div className="text-[11px] text-gray-500">Presence Penalty</div>
                <Input
                  type="number"
                  value={studioSettings.targetAi.openai.presence_penalty ?? ""}
                  onChange={(e: React.ChangeEvent<HTMLInputElement>) => {
                    const raw = e.target.value;
                    const next = raw === "" ? null : Number(raw);
                    if (raw !== "" && !Number.isFinite(next)) return;
                    setStudioSettings((prev: ImageStudioSettings) => ({
                      ...prev,
                      targetAi: { ...prev.targetAi, openai: { ...prev.targetAi.openai, presence_penalty: next } },
                    }));
                  }}
                  className="h-8"
                  min={-2}
                  max={2}
                  step={0.1}
                />
              </div>
              <div className="space-y-1">
                <div className="text-[11px] text-gray-500">Frequency Penalty</div>
                <Input
                  type="number"
                  value={studioSettings.targetAi.openai.frequency_penalty ?? ""}
                  onChange={(e: React.ChangeEvent<HTMLInputElement>) => {
                    const raw = e.target.value;
                    const next = raw === "" ? null : Number(raw);
                    if (raw !== "" && !Number.isFinite(next)) return;
                    setStudioSettings((prev: ImageStudioSettings) => ({
                      ...prev,
                      targetAi: { ...prev.targetAi, openai: { ...prev.targetAi.openai, frequency_penalty: next } },
                    }));
                  }}
                  className="h-8"
                  min={-2}
                  max={2}
                  step={0.1}
                />
              </div>
            </div>

            <div className="grid grid-cols-2 gap-2">
              <label className="flex items-center gap-2 text-xs text-gray-200">
                <input
                  type="checkbox"
                  checked={studioSettings.targetAi.openai.stream}
                  onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
                    setStudioSettings((prev: ImageStudioSettings) => ({
                      ...prev,
                      targetAi: { ...prev.targetAi, openai: { ...prev.targetAi.openai, stream: e.target.checked } },
                    }))
                  }
                />
                Stream
              </label>

              <div className="space-y-1">
                <div className="text-[11px] text-gray-500">Tool Choice</div>
                <Select
                  value={studioSettings.targetAi.openai.tool_choice ?? "__null__"}
                  onValueChange={(value: string) =>
                    setStudioSettings((prev: ImageStudioSettings) => ({
                      ...prev,
                      targetAi: {
                        ...prev.targetAi,
                        openai: { ...prev.targetAi.openai, tool_choice: value === "__null__" ? null : value === "none" ? "none" : "auto" },
                      },
                    }))
                  }
                >
                  <SelectTrigger className="h-8">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="__null__">Default</SelectItem>
                    <SelectItem value="auto">auto</SelectItem>
                    <SelectItem value="none">none</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-2">
              <div className="space-y-1">
                <div className="text-[11px] text-gray-500">Reasoning Effort</div>
                <Select
                  value={studioSettings.targetAi.openai.reasoning_effort ?? "__null__"}
                  onValueChange={(value: string) =>
                    setStudioSettings((prev: ImageStudioSettings) => ({
                      ...prev,
                      targetAi: {
                        ...prev.targetAi,
                        openai: {
                          ...prev.targetAi.openai,
                          reasoning_effort: value === "__null__" ? null : (value as ImageStudioSettings["targetAi"]["openai"]["reasoning_effort"]),
                        },
                      },
                    }))
                  }
                >
                  <SelectTrigger className="h-8">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="__null__">Default</SelectItem>
                    <SelectItem value="low">low</SelectItem>
                    <SelectItem value="medium">medium</SelectItem>
                    <SelectItem value="high">high</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-1">
                <div className="text-[11px] text-gray-500">Response Format</div>
                <Select
                  value={studioSettings.targetAi.openai.response_format ?? "__null__"}
                  onValueChange={(value: string) =>
                    setStudioSettings((prev: ImageStudioSettings) => ({
                      ...prev,
                      targetAi: {
                        ...prev.targetAi,
                        openai: {
                          ...prev.targetAi.openai,
                          response_format: value === "__null__" ? null : value === "json" ? "json" : "text",
                        },
                      },
                    }))
                  }
                >
                  <SelectTrigger className="h-8">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="__null__">Default</SelectItem>
                    <SelectItem value="text">text</SelectItem>
                    <SelectItem value="json">json</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-2">
              <div className="space-y-1">
                <div className="text-[11px] text-gray-500">User (optional)</div>
                <Input
                  value={studioSettings.targetAi.openai.user ?? ""}
                  onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
                    setStudioSettings((prev: ImageStudioSettings) => ({
                      ...prev,
                      targetAi: {
                        ...prev.targetAi,
                        openai: { ...prev.targetAi.openai, user: e.target.value.trim() ? e.target.value : null },
                      },
                    }))
                  }
                  className="h-8"
                  placeholder="e.g. user_123"
                />
              </div>
              <div className="text-[11px] text-gray-500">
                Tip: store your API key at <span className="text-gray-300">/admin/settings/ai</span>.
              </div>
            </div>

            {studioSettings.targetAi.openai.api === "images" ? (
              <div className="space-y-2 rounded border border-border/60 bg-card/30 p-2">
                <div className="text-xs text-gray-400">Images API options</div>

                <div className="grid grid-cols-2 gap-2">
                  <div className="space-y-1">
                    <div className="text-[11px] text-gray-500">Size</div>
                    <Input
                      value={studioSettings.targetAi.openai.image.size ?? ""}
                      onChange={(e: React.ChangeEvent<HTMLInputElement>) =>
                        setStudioSettings((prev: ImageStudioSettings) => ({
                          ...prev,
                          targetAi: {
                            ...prev.targetAi,
                            openai: {
                              ...prev.targetAi.openai,
                              image: { ...prev.targetAi.openai.image, size: e.target.value.trim() ? e.target.value : null },
                            },
                          },
                        }))
                      }
                      className="h-8"
                      placeholder="e.g. 1536x1024"
                    />
                  </div>
                  <div className="space-y-1">
                    <div className="text-[11px] text-gray-500">Quality</div>
                    <Select
                      value={studioSettings.targetAi.openai.image.quality ?? "__null__"}
                      onValueChange={(value: string) =>
                        setStudioSettings((prev: ImageStudioSettings) => ({
                          ...prev,
                          targetAi: {
                            ...prev.targetAi,
                            openai: {
                              ...prev.targetAi.openai,
                              image: {
                                ...prev.targetAi.openai.image,
                                quality: value === "__null__" ? null : value === "high" ? "high" : "standard",
                              },
                            },
                          },
                        }))
                      }
                    >
                      <SelectTrigger className="h-8">
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="__null__">Default</SelectItem>
                        <SelectItem value="standard">standard</SelectItem>
                        <SelectItem value="high">high</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-2">
                  <div className="space-y-1">
                    <div className="text-[11px] text-gray-500">Background</div>
                    <Select
                      value={studioSettings.targetAi.openai.image.background ?? "__null__"}
                      onValueChange={(value: string) =>
                        setStudioSettings((prev: ImageStudioSettings) => ({
                          ...prev,
                          targetAi: {
                            ...prev.targetAi,
                            openai: {
                              ...prev.targetAi.openai,
                              image: {
                                ...prev.targetAi.openai.image,
                                background: value === "__null__" ? null : value === "transparent" ? "transparent" : "white",
                              },
                            },
                          },
                        }))
                      }
                    >
                      <SelectTrigger className="h-8">
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="__null__">Default</SelectItem>
                        <SelectItem value="white">white</SelectItem>
                        <SelectItem value="transparent">transparent</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                  <div className="space-y-1">
                    <div className="text-[11px] text-gray-500">Format</div>
                    <Select
                      value={studioSettings.targetAi.openai.image.format ?? "png"}
                      onValueChange={(value: string) =>
                        setStudioSettings((prev: ImageStudioSettings) => ({
                          ...prev,
                          targetAi: {
                            ...prev.targetAi,
                            openai: {
                              ...prev.targetAi.openai,
                              image: { ...prev.targetAi.openai.image, format: value === "jpeg" ? "jpeg" : "png" },
                            },
                          },
                        }))
                      }
                    >
                      <SelectTrigger className="h-8">
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="png">png</SelectItem>
                        <SelectItem value="jpeg">jpeg</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </div>

                <div className="grid grid-cols-2 gap-2">
                  <div className="space-y-1">
                    <div className="text-[11px] text-gray-500">N</div>
                    <Input
                      type="number"
                      value={studioSettings.targetAi.openai.image.n ?? ""}
                      onChange={(e: React.ChangeEvent<HTMLInputElement>) => {
                        const raw = e.target.value;
                        const next = raw === "" ? null : Number(raw);
                        if (raw !== "" && (!Number.isFinite(next) || !Number.isInteger(next))) return;
                        setStudioSettings((prev: ImageStudioSettings) => ({
                          ...prev,
                          targetAi: {
                            ...prev.targetAi,
                            openai: {
                              ...prev.targetAi.openai,
                              image: { ...prev.targetAi.openai.image, n: next },
                            },
                          },
                        }));
                      }}
                      className="h-8"
                      min={1}
                      step={1}
                    />
                  </div>
                  <div className="text-[11px] text-gray-500">
                    For edits, keep <span className="text-gray-300">N=1</span>.
                  </div>
                </div>
              </div>
            ) : null}

            <div className="space-y-1">
              <div className="text-[11px] text-gray-500">Advanced Overrides (JSON)</div>
              <Textarea
                value={advancedOverridesText}
                onChange={(e: React.ChangeEvent<HTMLTextAreaElement>) => handleAdvancedOverridesChange(e.target.value)}
                className="h-28 font-mono text-[11px]"
                placeholder='e.g. {"metadata":{"project":"milkbar-001"}}'
              />
              {advancedOverridesError ? (
                <div className="text-[11px] text-red-300">{advancedOverridesError}</div>
              ) : null}
            </div>
          </div>
        </div>
      </SectionPanel>
    </div>
  );
}

import { z } from "zod";

