"use client";

import { Button, Label, UnifiedSelect, useToast, SectionHeader, SectionPanel } from "@/shared/ui";
import { useState, useEffect } from "react";
import { logClientError } from "@/features/observability";
import { fetchSettingsCached, invalidateSettingsCache } from "@/shared/api/settings-client";

const STATIC_TRANSLATION_MODELS = [
  { value: "gpt-4o", label: "GPT-4o", description: "OpenAI" },
  { value: "gpt-4-turbo", label: "GPT-4 Turbo", description: "OpenAI" },
  { value: "gpt-3.5-turbo", label: "GPT-3.5 Turbo", description: "OpenAI" },
];

export function AiTranslationSettings(): React.JSX.Element {
  const [translationModel, setTranslationModel] = useState("");
  const [ollamaModels, setOllamaModels] = useState<{ value: string; label: string; description: string }[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const { toast } = useToast();

  useEffect(() => {
    const loadData = async (): Promise<void> => {
      try {
        const data = await fetchSettingsCached();
        const settingsMap = new Map(data.map((item) => [item.key, item.value]));

        setTranslationModel(settingsMap.get("ai_translation_model") || "gpt-4o");

        const chatbotRes = await fetch("/api/chatbot");
        if (chatbotRes.ok) {
          const data = await chatbotRes.json() as { models?: string[] };
          if (Array.isArray(data.models)) {
            setOllamaModels(data.models.map((name: string) => ({ value: name, label: name, description: "Ollama" })));
          }
        }
      } catch (error) {
        logClientError(error, { context: { source: "AiTranslationSettings", action: "loadData" } });
        toast("Failed to load configuration.", { variant: "error" });
      } finally {
        setLoading(false);
      }
    };
    void loadData();
  }, [toast]);

  const handleSave = async (): Promise<void> => {
    setSaving(true);
    try {
      await fetch("/api/settings", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          key: "ai_translation_model",
          value: translationModel,
        }),
      });
      invalidateSettingsCache();

      toast("Settings saved.", { variant: "success" });
    } catch (error) {
      logClientError(error, { context: { source: "AiTranslationSettings", action: "handleSave" } });
      toast("Failed to save.", { variant: "error" });
    } finally {
      setSaving(false);
    }
  };

  if (loading) return <div className="text-sm text-gray-400">Loading settings...</div>;

  return (
    <div className="space-y-8">
      <SectionHeader
        title="AI Translation Configuration"
        description="Configure the AI model used for translating product names and descriptions."
        size="md"
      />

      <SectionPanel variant="subtle" className="space-y-6">
        <div className="max-w-md space-y-4">
          <div className="space-y-2">
            <Label>Translation Model</Label>
            <UnifiedSelect
              value={translationModel}
              onValueChange={setTranslationModel}
              options={[...STATIC_TRANSLATION_MODELS, ...ollamaModels]}
            />
            <p className="text-xs text-gray-500 mt-2">
              This model will be used to translate product names and descriptions into
              languages associated with the product&apos;s catalogs.
            </p>
          </div>

          <SectionPanel variant="subtle-compact" className="border border-border">
            <h4 className="text-sm font-medium text-white mb-2">How It Works</h4>
            <ul className="text-xs text-gray-400 space-y-1 list-disc list-inside">
              <li>
                Translation requests can be triggered from the Product Edit/Create panel
              </li>
              <li>
                If the product belongs to catalogs, it translates to those catalog languages
              </li>
              <li>
                If no catalogs are assigned, it translates to all available languages
              </li>
              <li>
                Translations are processed as AI jobs and can be monitored on the Jobs page
              </li>
            </ul>
          </SectionPanel>
        </div>
      </SectionPanel>

      <div className="flex justify-end">
        <Button
          onClick={() => void handleSave()}
          disabled={saving}
          className="bg-white text-black hover:bg-gray-200"
        >
          {saving ? "Saving..." : "Save Configuration"}
        </Button>
      </div>
    </div>
  );
}

"use client";

import React, { useCallback, useMemo, useState } from "react";
import { VectorDrawingCanvas } from "./VectorDrawingCanvas";
import { VectorDrawingToolbar, type VectorDrawingToolbarVariant } from "./VectorDrawingToolbar";
import { smoothShape, simplifyShape } from "../geometry";
import { vectorShapesToPath } from "../utils";
import type { VectorShape, VectorToolMode } from "../types";

export type VectorDrawingOutput = {
  shapes: VectorShape[];
  path: string;
  points: Array<{ shapeId: string; points: VectorShape["points"] }>;
};

export type VectorDrawingProps = {
  value?: VectorShape[];
  defaultValue?: VectorShape[];
  onChange?: (next: VectorShape[]) => void;
  onOutput?: (output: VectorDrawingOutput) => void;
  tool?: VectorToolMode;
  defaultTool?: VectorToolMode;
  onToolChange?: (tool: VectorToolMode) => void;
  toolbarVariant?: VectorDrawingToolbarVariant;
  toolbarClassName?: string;
  className?: string;
  canvasClassName?: string;
  allowWithoutImage?: boolean;
  showEmptyState?: boolean;
  emptyStateLabel?: string;
  imageSrc?: string | null;
  brushRadius?: number;
  activeShapeId?: string | null;
  selectedPointIndex?: number | null;
  onSelectShape?: (id: string | null) => void;
  onSelectPoint?: (index: number | null) => void;
};

const buildOutput = (shapes: VectorShape[]): VectorDrawingOutput => ({
  shapes,
  path: vectorShapesToPath(shapes),
  points: shapes.map((shape) => ({ shapeId: shape.id, points: shape.points })),
});

export function VectorDrawing({
  value,
  defaultValue,
  onChange,
  onOutput,
  tool,
  defaultTool = "select",
  onToolChange,
  toolbarVariant = "full",
  toolbarClassName,
  className,
  canvasClassName,
  allowWithoutImage,
  showEmptyState,
  emptyStateLabel,
  imageSrc,
  brushRadius,
  activeShapeId,
  selectedPointIndex,
  onSelectShape,
  onSelectPoint,
}: VectorDrawingProps): React.JSX.Element {
  const [internalShapes, setInternalShapes] = useState<VectorShape[]>(defaultValue ?? []);
  const [internalTool, setInternalTool] = useState<VectorToolMode>(defaultTool);

  const shapes = value ?? internalShapes;
  const currentTool = tool ?? internalTool;

  const handleChange = useCallback(
    (nextShapes: VectorShape[]) => {
      if (!value) setInternalShapes(nextShapes);
      onChange?.(nextShapes);
      onOutput?.(buildOutput(nextShapes));
    },
    [onChange, onOutput, value]
  );

  const handleToolChange = useCallback(
    (nextTool: VectorToolMode) => {
      if (!tool) setInternalTool(nextTool);
      onToolChange?.(nextTool);
    },
    [onToolChange, tool]
  );

  const output = useMemo(() => buildOutput(shapes), [shapes]);

  const handleSmooth = useCallback((): void => {
    handleChange(shapes.map((shape) => smoothShape(shape, 1)));
  }, [handleChange, shapes]);

  const handleSimplify = useCallback((): void => {
    handleChange(shapes.map((shape) => simplifyShape(shape, 0.0025)));
  }, [handleChange, shapes]);

  const resolvedBrushRadius = brushRadius ?? 6;
  const resolvedImageSrc = imageSrc ?? null;
  const resolvedActiveShapeId = activeShapeId ?? null;
  const resolvedSelectedPointIndex = selectedPointIndex ?? null;
  const handleSelectShape = onSelectShape ?? (() => {});

  return (
    <div className={className}>
      <VectorDrawingCanvas
        {...(allowWithoutImage !== undefined ? { allowWithoutImage } : {})}
        {...(showEmptyState !== undefined ? { showEmptyState } : {})}
        {...(emptyStateLabel !== undefined ? { emptyStateLabel } : {})}
        src={resolvedImageSrc}
        tool={currentTool}
        shapes={shapes}
        onChange={handleChange}
        brushRadius={resolvedBrushRadius}
        activeShapeId={resolvedActiveShapeId}
        selectedPointIndex={resolvedSelectedPointIndex}
        onSelectShape={handleSelectShape}
        {...(onSelectPoint ? { onSelectPoint } : {})}
        {...(canvasClassName ? { className: canvasClassName } : {})}
      />
      <VectorDrawingToolbar
        {...(toolbarClassName ? { className: toolbarClassName } : {})}
        tool={currentTool}
        onSelectTool={handleToolChange}
        onSmooth={handleSmooth}
        onSimplify={handleSimplify}
        variant={toolbarVariant}
      />
      {onOutput ? null : <span className="sr-only">{output.path}</span>}
    </div>
  );
}

"use client";

import React from "react";
import {
  Brush,
  Check,
  Circle,
  Filter,
  Lasso,
  MousePointer2,
  Pentagon,
  RectangleHorizontal,
  RotateCcw,
  Sparkles,
  Trash2,
  Unlink,
} from "lucide-react";

import { Button, Tooltip } from "@/shared/ui";
import { cn } from "@/shared/utils";
import type { VectorToolMode } from "../types";

export type VectorDrawingToolbarVariant = "full" | "min";

export interface VectorDrawingToolbarProps {
  tool: VectorToolMode;
  onSelectTool: (tool: VectorToolMode) => void;
  onUndo?: () => void;
  onClose?: () => void;
  onDetach?: () => void;
  onClear?: () => void;
  onSmooth?: () => void;
  onSimplify?: () => void;
  disableUndo?: boolean;
  disableClose?: boolean;
  disableDetach?: boolean;
  disableClear?: boolean;
  disableSmooth?: boolean;
  disableSimplify?: boolean;
  className?: string;
  variant?: VectorDrawingToolbarVariant;
}

type ToolOption = {
  key: VectorToolMode;
  label: string;
  icon: React.ReactNode;
};

const FULL_TOOLS: ToolOption[] = [
  { key: "select", label: "Select", icon: <MousePointer2 className="size-4" /> },
  { key: "polygon", label: "Polygon", icon: <Pentagon className="size-4" /> },
  { key: "lasso", label: "Lasso", icon: <Lasso className="size-4" /> },
  { key: "rect", label: "Rectangle", icon: <RectangleHorizontal className="size-4" /> },
  { key: "ellipse", label: "Ellipse", icon: <Circle className="size-4" /> },
  { key: "brush", label: "Brush", icon: <Brush className="size-4" /> },
];

const MIN_TOOLS: ToolOption[] = [
  { key: "select", label: "Edit", icon: <MousePointer2 className="size-4" /> },
  { key: "polygon", label: "Pen", icon: <Pentagon className="size-4" /> },
];

export function VectorDrawingToolbar({
  tool,
  onSelectTool,
  onUndo,
  onClose,
  onDetach,
  onClear,
  onSmooth,
  onSimplify,
  disableUndo,
  disableClose,
  disableDetach,
  disableClear,
  disableSmooth,
  disableSimplify,
  className,
  variant = "full",
}: VectorDrawingToolbarProps): React.JSX.Element {
  const toolOptions = variant === "min" ? MIN_TOOLS : FULL_TOOLS;
  const hasActions = Boolean(onUndo || onClose || onDetach || onClear || onSmooth || onSimplify);

  return (
    <div
      className={cn(
        "flex items-center gap-2 rounded-full border border-border/60 bg-card/80 px-3 py-2 shadow-lg",
        className
      )}
    >
      {toolOptions.map((option) => (
        <Tooltip key={option.key} content={option.label}>
          <Button
            type="button"
            variant={tool === option.key ? "secondary" : "outline"}
            size="icon"
            onClick={() => onSelectTool(option.key)}
          >
            {option.icon}
          </Button>
        </Tooltip>
      ))}
      {hasActions ? <div className="mx-1 h-6 w-px bg-border" /> : null}
      {onUndo ? (
        <Tooltip content="Undo last point">
          <Button
            type="button"
            variant="outline"
            size="icon"
            onClick={onUndo}
            disabled={disableUndo}
          >
            <RotateCcw className="size-4" />
          </Button>
        </Tooltip>
      ) : null}
      {onClose ? (
        <Tooltip content="Close polygon">
          <Button
            type="button"
            variant="outline"
            size="icon"
            onClick={onClose}
            disabled={disableClose}
          >
            <Check className="size-4" />
          </Button>
        </Tooltip>
      ) : null}
      {onDetach ? (
        <Tooltip content="Detach polygon">
          <Button
            type="button"
            variant="outline"
            size="icon"
            onClick={onDetach}
            disabled={disableDetach}
          >
            <Unlink className="size-4" />
          </Button>
        </Tooltip>
      ) : null}
      {onClear ? (
        <Tooltip content="Clear shapes">
          <Button
            type="button"
            variant="outline"
            size="icon"
            onClick={onClear}
            disabled={disableClear}
          >
            <Trash2 className="size-4" />
          </Button>
        </Tooltip>
      ) : null}
      {onSmooth ? (
        <Tooltip content="Smooth path">
          <Button
            type="button"
            variant="outline"
            size="icon"
            onClick={onSmooth}
            disabled={disableSmooth}
          >
            <Sparkles className="size-4" />
          </Button>
        </Tooltip>
      ) : null}
      {onSimplify ? (
        <Tooltip content="Simplify path">
          <Button
            type="button"
            variant="outline"
            size="icon"
            onClick={onSimplify}
            disabled={disableSimplify}
          >
            <Filter className="size-4" />
          </Button>
        </Tooltip>
      ) : null}
    </div>
  );
}

