"use client";

import React, { createContext, useContext, useMemo } from "react";
import { useSettingsMap } from "@/shared/hooks/use-settings";

type SettingsStoreValue = {
  map: Map<string, string>;
  isLoading: boolean;
  isFetching: boolean;
  error: Error | null;
  get: (key: string) => string | undefined;
  getBoolean: (key: string, fallback?: boolean) => boolean;
  getNumber: (key: string, fallback?: number) => number | undefined;
  refetch: () => void;
};

const SettingsStoreContext = createContext<SettingsStoreValue | null>(null);

const parseBoolean = (value: string | undefined, fallback: boolean): boolean => {
  if (value === undefined) return fallback;
  return ["true", "1", "yes", "on"].includes(value.toLowerCase());
};

const parseNumber = (value: string | undefined, fallback?: number): number | undefined => {
  if (value === undefined) return fallback;
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
};

export function SettingsStoreProvider({
  children,
}: {
  children: React.ReactNode;
}): React.JSX.Element {
  const settingsQuery = useSettingsMap();

  const value = useMemo<SettingsStoreValue>(() => {
    const map = settingsQuery.data ?? new Map<string, string>();
    return {
      map,
      isLoading: settingsQuery.isLoading,
      isFetching: settingsQuery.isFetching,
      error: settingsQuery.error ?? null,
      get: (key: string) => map.get(key),
      getBoolean: (key: string, fallback: boolean = false) =>
        parseBoolean(map.get(key), fallback),
      getNumber: (key: string, fallback?: number) =>
        parseNumber(map.get(key), fallback),
      refetch: () => {
        void settingsQuery.refetch();
      },
    };
  }, [
    settingsQuery.data,
    settingsQuery.isLoading,
    settingsQuery.isFetching,
    settingsQuery.error,
    settingsQuery.refetch,
  ]);

  return (
    <SettingsStoreContext.Provider value={value}>
      {children}
    </SettingsStoreContext.Provider>
  );
}

export function useSettingsStore(): SettingsStoreValue {
  const context = useContext(SettingsStoreContext);
  if (!context) {
    throw new Error("useSettingsStore must be used within SettingsStoreProvider");
  }
  return context;
}

"use client";

import { useEffect } from "react";

const normalizeBadHostPath = (host: string, path: string): string | null => {
  const hostPrefix = `/${host}`;
  if (path === hostPrefix) return "/";
  if (path.startsWith(`${hostPrefix}/`)) {
    const next = path.slice(hostPrefix.length);
    return next.length ? next : "/";
  }
  return null;
};

const normalizeNavigationUrl = (input: string, host: string): string => {
  const trimmed = input.trim();
  if (!trimmed) return trimmed;
  if (/^[a-zA-Z][a-zA-Z0-9+.-]*:/.test(trimmed)) return trimmed;
  if (trimmed.startsWith(`//${host}`)) {
    return `${window.location.protocol}${trimmed}`;
  }
  if (trimmed === host || trimmed === `${host}/`) {
    return window.location.origin;
  }
  if (trimmed.startsWith(`${host}/`)) {
    return `${window.location.protocol}//${trimmed}`;
  }
  if (trimmed.startsWith(`/${host}`)) {
    const normalized = normalizeBadHostPath(host, trimmed);
    return normalized ?? trimmed;
  }
  return trimmed;
};

export function UrlGuardProvider(): null {
  useEffect(() => {
    if (typeof window === "undefined") return;
    const host = window.location.host;
    const hostPrefix = `/${host}`;

    const normalizedPath = normalizeBadHostPath(host, window.location.pathname);
    if (normalizedPath) {
      const nextUrl = `${normalizedPath}${window.location.search}${window.location.hash}`;
      window.history.replaceState(null, "", nextUrl);
      // eslint-disable-next-line no-console
      console.warn("[url-guard] normalized path", {
        from: window.location.pathname,
        to: normalizedPath,
      });
    }

    const wrap = (original: (url: string, ...rest: unknown[]) => void) => {
      return (url: string, ...rest: unknown[]) => {
        const next = normalizeNavigationUrl(url, host);
        if (next.startsWith(hostPrefix) || next.startsWith(`//${host}`)) {
          // eslint-disable-next-line no-console
          console.warn("[url-guard] blocked invalid navigation", { url, normalized: next, stack: new Error().stack });
        }
        return original(next, ...rest);
      };
    };

    try {
      const originalAssign = window.location.assign.bind(window.location);
      const originalReplace = window.location.replace.bind(window.location);
      window.location.assign = wrap(originalAssign);
      window.location.replace = wrap(originalReplace);
    } catch {
      // Ignore if location is not writable in this environment.
    }

    const wrapHistory = (
      original: (data: unknown, title: string, url?: string | URL | null) => void,
      label: string
    ) => {
      return (data: unknown, title: string, url?: string | URL | null) => {
        if (typeof url === "string") {
          const next = normalizeNavigationUrl(url, host);
          if (next.startsWith(hostPrefix) || next.startsWith(`//${host}`)) {
            // eslint-disable-next-line no-console
            console.warn(`[url-guard] ${label} invalid`, { url, normalized: next, stack: new Error().stack });
          }
          return original.call(window.history, data, title, next);
        }
        return original.call(window.history, data, title, url as string | URL | null);
      };
    };

    try {
      const originalPush = window.history.pushState.bind(window.history);
      const originalReplaceState = window.history.replaceState.bind(window.history);
      window.history.pushState = wrapHistory(originalPush, "pushState");
      window.history.replaceState = wrapHistory(originalReplaceState, "replaceState");
    } catch {
      // Ignore history patch failures.
    }

    const onClick = (event: MouseEvent) => {
      const target = event.target as HTMLElement | null;
      if (!target) return;
      const anchor = target.closest("a") as HTMLAnchorElement | null;
      if (!anchor) return;
      const href = anchor.getAttribute("href");
      if (!href) return;
      const normalized = normalizeNavigationUrl(href, host);
      if (normalized !== href) {
        // eslint-disable-next-line no-console
        console.warn("[url-guard] normalized anchor", { href, normalized, stack: new Error().stack });
        anchor.setAttribute("href", normalized);
      }
    };
    window.addEventListener("click", onClick, true);

    return () => {
      window.removeEventListener("click", onClick, true);
    };
  }, []);

  return null;
}

"use client";

import React, { useEffect, useMemo, useRef, useState } from "react";
import { createPortal } from "react-dom";
import { cn } from "@/shared/utils";

export type TreeContextMenuItem = {
  id: string;
  label?: string | undefined;
  onSelect?: (() => void) | undefined;
  disabled?: boolean | undefined;
  tone?: ("default" | "danger") | undefined;
  icon?: React.ReactNode | undefined;
  separator?: boolean | undefined;
};

export interface TreeContextMenuProps {
  items: TreeContextMenuItem[];
  align?: "start" | "center" | "end";
  sideOffset?: number;
  className?: string;
  children: React.ReactNode;
}

export function TreeContextMenu({
  items,
  align = "start",
  sideOffset = 4,
  className,
  children,
}: TreeContextMenuProps): React.JSX.Element {
  const [open, setOpen] = useState(false);
  const [position, setPosition] = useState<{ x: number; y: number }>({ x: 0, y: 0 });
  const menuRef = useRef<HTMLDivElement | null>(null);
  const [mounted, setMounted] = useState(false);
  const hasItems = useMemo(
    () => items.some((item) => item.separator || item.label),
    [items]
  );

  if (!hasItems) {
    return <>{children}</>;
  }

  useEffect((): void => {
    setMounted(true);
  }, []);

  useEffect((): (() => void) | void => {
    if (!open) return undefined;

    const handlePointer = (event: MouseEvent): void => {
      const target = event.target as Node | null;
      if (!menuRef.current || (target && menuRef.current.contains(target))) return;
      setOpen(false);
    };

    const handleEscape = (event: KeyboardEvent): void => {
      if (event.key === "Escape") setOpen(false);
    };

    const handleScroll = (): void => setOpen(false);

    window.addEventListener("mousedown", handlePointer);
    window.addEventListener("contextmenu", handlePointer);
    window.addEventListener("keydown", handleEscape);
    window.addEventListener("scroll", handleScroll, true);
    window.addEventListener("resize", handleScroll);

    return (): void => {
      window.removeEventListener("mousedown", handlePointer);
      window.removeEventListener("contextmenu", handlePointer);
      window.removeEventListener("keydown", handleEscape);
      window.removeEventListener("scroll", handleScroll, true);
      window.removeEventListener("resize", handleScroll);
    };
  }, [open]);

  useEffect((): void => {
    if (!open || !menuRef.current) return;
    const menu = menuRef.current;
    const rect = menu.getBoundingClientRect();
    let nextX = position.x + (align === "center" ? -rect.width / 2 : align === "end" ? -rect.width : 0);
    let nextY = position.y + sideOffset;

    if (nextX + rect.width > window.innerWidth) {
      nextX = Math.max(8, window.innerWidth - rect.width - 8);
    }
    if (nextX < 8) nextX = 8;
    if (nextY + rect.height > window.innerHeight) {
      nextY = Math.max(8, position.y - rect.height - sideOffset);
    }
    if (nextY < 8) nextY = 8;

    if (nextX !== position.x || nextY !== position.y) {
      setPosition({ x: nextX, y: nextY });
    }
  }, [open, align, sideOffset, position]);

  const menu = open && mounted ? createPortal(
    <div
      ref={menuRef}
      className="z-50 min-w-[8rem] overflow-hidden rounded-md border border-border/50 bg-popover/90 p-1 text-popover-foreground shadow-md backdrop-blur-md"
      style={{ position: "fixed", top: position.y, left: position.x }}
      role="menu"
    >
      {items.map((item) => {
        if (item.separator) {
          return <div key={item.id} className="-mx-1 my-1 h-px bg-foreground/10" />;
        }
        return (
          <button
            key={item.id}
            type="button"
            onClick={() => {
              if (item.disabled) return;
              item.onSelect?.();
              setOpen(false);
            }}
            className={cn(
              "relative flex w-full cursor-default select-none items-center rounded-sm px-2 py-1.5 text-sm outline-none transition-colors",
              item.disabled ? "pointer-events-none opacity-50" : "hover:bg-foreground/10 focus:bg-foreground/10 focus:text-foreground",
              item.tone === "danger" && "text-red-300 hover:text-red-200"
            )}
            role="menuitem"
            disabled={item.disabled}
          >
            {item.icon ? <span className="mr-2 inline-flex size-4 items-center justify-center">{item.icon}</span> : null}
            {item.label}
          </button>
        );
      })}
    </div>,
    document.body
  ) : null;

  return (
    <>
      <span
        className={cn("contents", className)}
        onContextMenu={(event: React.MouseEvent): void => {
          event.preventDefault();
          setPosition({ x: event.clientX, y: event.clientY });
          setOpen(true);
        }}
      >
        {children}
      </span>
      {menu}
    </>
  );
}
